// Auth validation
const headerSecret = $input.first().json.headers?.['x-api-secret'] || $input.first().json.header?.['x-api-secret'] || '';
const expectedSecret = $env.API_SECRET || 'change-me-in-env';

if (headerSecret !== expectedSecret) {
  throw new Error('Unauthorized: invalid API secret');
}

const body = $input.first().json.body || {};
const message = body.message;
const history = body.history || [];

if (!message) {
  throw new Error('message is required');
}

return [{ json: { message, history, validated: true } }];

// Extract Claude's response content
const response = $input.first().json;

// Handle different response formats
let content = '';

if (response.content && Array.isArray(response.content)) {
  // Claude message format with content blocks
  content = response.content
    .filter(block => block.type === 'text')
    .map(block => block.text)
    .join('\n');
} else if (response.error) {
  throw new Error('Claude API error: ' + JSON.stringify(response.error));
} else if (typeof response === 'string') {
  content = response;
} else {
  content = JSON.stringify(response);
}

return [{ json: { response: content.trim() } }];

// Format messages for Claude API
// Build the messages array combining history + current message
const input = $input.first().json;
const history = input.history || [];
const message = input.message;

// Ensure history items have proper format
const formattedHistory = history.map(h => ({
  role: h.role,
  content: h.content
}));

// Add current message
formattedHistory.push({
  role: 'user',
  content: message
});

return [{ json: { formattedHistory } }];
